// ── getDomainCounts — per-domain issue summary ────────────────────────────────
export function getDomainCounts(center, reg, liveData = {}) {
  return getDomainFields(center, reg, liveData).map(d => {
    const issues = d.fields.filter(f => f.status === 'missing' || f.status === 'atrisk');
    const nodata = d.fields.filter(f => f.status === 'nodata');
    const met    = d.fields.filter(f => f.status === 'compliant');
    return { id:d.id, dNum:d.dNum, label:d.label, issues, nodata, met, topIssue: issues[0] || nodata[0] || null };
  });
}

// ── getFieldByKey — look up a field definition by dataKey ─────────────────────
export function getFieldByKey(dataKey, center, reg, liveData = {}) {
  for (const domain of getDomainFields(center, reg, liveData)) {
    const field = domain.fields.find(f => f.dataKey === dataKey);
    if (field) return { ...field, domain };
  }
  return null;
}

// ── getFieldByNum — look up by fieldNum (e.g. 'D1-001') ──────────────────────
export function getFieldByNum(fieldNum, center, reg, liveData = {}) {
  for (const domain of getDomainFields(center, reg, liveData)) {
    const field = domain.fields.find(f => f.fieldNum === fieldNum);
    if (field) return { ...field, domain };
  }
  return null;
}